impl Solution { pub fn soup_servings(n: i32) -> f64 { if n > 4800 { return 1.0; } let n = (n + 24) / 25; let mut black_memo = std::collections::HashMap::new(); fn dp(a: i32, b: i32, memo: &mut std::collections::HashMap<(i32, i32), f64>) -> f64 { if a <= 0 && b <= 0 { return 0.5; } if a <= 0 { return 1.0; } if b <= 0 { return 0.0; } if let Some(&res) = memo.get(&(a, b)) { return res; } let res = 0.25 * (dp(a-4, b, memo) + dp(a-3, b-1, memo) + dp(a-2, b-2, memo) + dp(a-1, b-3, memo)); memo.insert((a, b), res); res } dp(n, n, &mut black_memo) } }